        "viz_wxQKoTfQ": {
            "dataSources": {
                "primary": "ds_MR3oFccM"
            },
            "options": {
                "legendDisplay": "top",
                "xAxisTitleText": "Time",
                "yAxisTitleText": "Uncorrectable ECC Errors - $unccstats$"
            },
            "showLastUpdated": false,
            "showProgressBar": false,
            "title": "Uncorrectable ECC Error Trend: Domain: ($uncorrectable_domain_name$), Name: ($uncorrectable_event_name$)",
            "type": "splunk.line",
            "hideWhenNoData": true
        }
    },
    "dataSources": {
        "ds_1KzLVfQu": {
            "name": "Network RX CRC Error Trend search",
            "options": {
                "query": "| tstats fillnull_value=\"-\" `cisco_intersight_summariesonly` count, latest(cisco_intersight.cisco_intersight_network.network_domain_name) as \"Domain Name\", latest(cisco_intersight.cisco_intersight_network.network_parent_name) as \"Parent Name\", latest(cisco_intersight.cisco_intersight_network.network_name) as \"Name\", avg(cisco_intersight.cisco_intersight_network.network_receive_crc_rate) as \"CRCrate\", avg(cisco_intersight.cisco_intersight_network.network_receive_crc_sum) as \"CRCsum\", latest(cisco_intersight.cisco_intersight_network.network_timestamp) as \"Event Time\" from datamodel=Cisco_Intersight where nodename=cisco_intersight.cisco_intersight_network AND cisco_intersight.cisco_intersight_network.network_domain_name=\"$network_domainname$\" AND cisco_intersight.cisco_intersight_network.network_id=\"$crc_event_id$\" by _time, cisco_intersight.cisco_intersight_network.network_id span=15min\n| rename cisco_intersight.cisco_intersight_network.network_id as EventId\n| eval CRC=case(\"$netstats$\"=\"Average\", CRCrate, true(), CRCsum)\n| eval CRC = if(CRC > 0, round(CRC, 2), CRC) \n| rename CRC as \"$netstats$\"\n| timechart span=15min avg(\"$netstats$\") BY EventId",
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                },
                "refresh": "15m",
                "refreshType": "delay"
            },
            "type": "ds.search"
        },
        "ds_AJFcyLD6": {
            "name": "Correctable ECC errors - Table search",
            "options": {
                "query": "| tstats fillnull_value=\"-\" `cisco_intersight_summariesonly` count, latest(cisco_intersight.cisco_intersight_memory.memory_domain_name) as \"Intersight Domain\", latest(cisco_intersight.cisco_intersight_memory.memory_host_name) as \"Host Name\", latest(cisco_intersight.cisco_intersight_memory.memory_name) as Name, avg(cisco_intersight.cisco_intersight_memory.memory_correctable_ecc_errors_rate) as \"correctable_ecc_rate\", avg(cisco_intersight.cisco_intersight_memory.memory_correctable_ecc_errors_sum) as \"correctable_ecc_sum\", avg(cisco_intersight.cisco_intersight_memory.memory_correctable_ecc_errors_min) as \"correctable_ecc_min\", avg(cisco_intersight.cisco_intersight_memory.memory_correctable_ecc_errors_max) as \"correctable_ecc_max\", values(cisco_intersight.cisco_intersight_memory.memory_account_name) as account_name\n    from datamodel=Cisco_Intersight where nodename=cisco_intersight.cisco_intersight_memory AND cisco_intersight.cisco_intersight_memory.memory_domain_id=\"*\" AND cisco_intersight.cisco_intersight_memory.memory_domain_name=\"$correctable_memory_domainname$\" AND cisco_intersight.cisco_intersight_memory.memory_host_name=\"$correctable_memory_hostname$\" AND cisco_intersight.cisco_intersight_memory.memory_name=\"$correctable_memory_eventname$\" by cisco_intersight.cisco_intersight_memory.memory_id, cisco_intersight.cisco_intersight_memory.memory_account_name\n| search account_name IN ($ecc_account_name$)\n| eval correctable_ecc=case(\"$ccstats$\"=\"Average\", correctable_ecc_rate, \"$ccstats$\"=\"Minimum\", correctable_ecc_min, \"$ccstats$\"=\"Maximum\", correctable_ecc_max, true(), correctable_ecc_sum)\n| where \"correctable_ecc\" != \"null\"\n| eval correctable_ecc = if(correctable_ecc > 0, round(correctable_ecc, 2), correctable_ecc)\n| where \"$show_correctable_zero_values$\"=\"true\" OR correctable_ecc > 0\n| rename cisco_intersight.cisco_intersight_memory.memory_id as MemoryId, correctable_ecc as \"$ccstats$\"\n| rename MemoryId as _MemoryId\n| sort 0 -\"$ccstats$\" \n| table \"Intersight Domain\", \"Host Name\", _MemoryId, Name, \"$ccstats$\"",
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                },
                "refresh": "15m",
                "refreshType": "delay"
            },
            "type": "ds.search"
        },
        "ds_BCY0z3Dv": {
            "name": "ECC Account Name",
            "options": {
                "query": "| tstats fillnull_value=\"-\" `cisco_intersight_summariesonly` values(cisco_intersight.cisco_intersight_memory.memory_account_name) as account_name\n    from datamodel=Cisco_Intersight where nodename=cisco_intersight.cisco_intersight_memory by cisco_intersight.cisco_intersight_memory.memory_account_name\n| dedup account_name\n| table account_name",
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_DTYzHg0H_ds_ORR7wS2S": {
            "name": "Name 1 search copy 1",
            "options": {
                "query": "| tstats fillnull_value=\"-\" `cisco_intersight_summariesonly` latest(cisco_intersight.cisco_intersight_memory.memory_name) as memory_name, values(cisco_intersight.cisco_intersight_memory.memory_account_name) as account_name from datamodel=Cisco_Intersight where nodename=cisco_intersight.cisco_intersight_memory AND cisco_intersight.cisco_intersight_memory.memory_domain_name=\"$correctable_memory_domainname$\" AND cisco_intersight.cisco_intersight_memory.memory_host_name=\"$correctable_memory_hostname$\" AND cisco_intersight.cisco_intersight_memory.memory_name=\"$correctable_memory_eventname$\" by cisco_intersight.cisco_intersight_memory.memory_domain_name, cisco_intersight.cisco_intersight_memory.memory_host_name, cisco_intersight.cisco_intersight_memory.memory_id, cisco_intersight.cisco_intersight_memory.memory_account_name\n| search account_name IN ($un_ecc_account_name$)\n| dedup memory_name\n| table memory_name",
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_FjBCV5hN": {
            "name": "Correctable ECC Error Trend search",
            "options": {
